// HarfBuzz 14.2.1 wasm (harfbuzzjs 1.4.0, MIT), embedded as base64. See THIRD-PARTY.md.
// Decode an embedded base64 asset to bytes. Works in the browser and in node
// (both expose atob). Kept tiny and dependency-free so the vendor bundle stays
// self-contained; the byte cost of embedding is documented in docs/limits.md.
function decode(b64: string): Uint8Array {
  const bin = atob(b64);
  const out = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) out[i] = bin.charCodeAt(i);
  return out;
}

const B64 =
  "";

/** The HarfBuzz wasm module bytes. */
export const harfBuzzWasm: Uint8Array = decode(B64);
